import React, { useState, useEffect } from 'react';
import { useApp } from '../contexts/AppContext';
import { useLocation, useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import { Save, ArrowLeft } from 'lucide-react';

export default function FormCadastro() {
  const { grupos, addProduto, updateProduto } = useApp();
  const { state } = useLocation(); // Recebe o produto se for edição
  const navigate = useNavigate();
  
  const [formData, setFormData] = useState({
    nome: '', grupo_id: '', preco_venda: '', quantidade_estoque: ''
  });

  const [erros, setErros] = useState({});

  useEffect(() => {
    if (state?.item) {
      // Se estamos editando, preenche o formulário
      const gEncontrado = grupos.find(g => g.nome === state.item.grupo);
      setFormData({
        ...state.item,
        grupo_id: gEncontrado ? gEncontrado.id : ''
      });
    }
  }, [state, grupos]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    let tempErros = {};
    if (!formData.nome) tempErros.nome = true;
    if (!formData.grupo_id) tempErros.grupo = true;
    if (!formData.preco_venda) tempErros.preco = true;

    if (Object.keys(tempErros).length > 0) {
      setErros(tempErros);
      toast.error("Preencha todos os campos obrigatórios!");
      return;
    }

    const payload = {
      ...formData,
      grupo: grupos.find(g => g.id === parseInt(formData.grupo_id))?.nome,
      preco_venda: parseFloat(formData.preco_venda),
      quantidade_estoque: parseInt(formData.quantidade_estoque) || 0
    };

    const isEdit = !!state?.item;
    const sucesso = isEdit 
      ? await updateProduto(state.item.id, payload)
      : await addProduto(payload);

    if (sucesso) {
      navigate('/');
    }
  };

  return (
    <main className="mt-24 container mx-auto p-4 max-w-2xl">
      <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-gray-500 hover:text-blue-600 mb-4 transition">
        <ArrowLeft size={20} /> Voltar
      </button>

      <div className="bg-white p-8 rounded-2xl shadow-xl border border-gray-100">
        <h2 className="text-3xl font-extrabold mb-8 text-gray-800">
          {state?.item ? 'Editar Produto' : 'Cadastrar Novo Produto'}
        </h2>
        
        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-2">Nome do Produto *</label>
            <input 
              type="text" 
              className={`w-full p-3 border rounded-xl outline-none transition ${erros.nome ? 'border-red-500 bg-red-50' : 'focus:border-blue-500 border-gray-200'}`}
              value={formData.nome}
              onChange={(e) => setFormData({...formData, nome: e.target.value})}
            />
          </div>

          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-2">Categoria (Grupo) *</label>
            <select 
              className={`w-full p-3 border rounded-xl outline-none transition ${erros.grupo ? 'border-red-500 bg-red-50' : 'focus:border-blue-500 border-gray-200'}`}
              value={formData.grupo_id}
              onChange={(e) => setFormData({...formData, grupo_id: e.target.value})}
            >
              <option value="">Selecione um grupo</option>
              {grupos.map(g => <option key={g.id} value={g.id}>{g.nome}</option>)}
            </select>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Preço de Venda (R$) *</label>
              <input 
                type="number" step="0.01"
                className={`w-full p-3 border rounded-xl outline-none transition ${erros.preco ? 'border-red-500 bg-red-50' : 'focus:border-blue-500 border-gray-200'}`}
                value={formData.preco_venda}
                onChange={(e) => setFormData({...formData, preco_venda: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-2">Estoque Inicial</label>
              <input 
                type="number" 
                className="w-full p-3 border border-gray-200 rounded-xl outline-none focus:border-blue-500"
                value={formData.quantidade_estoque}
                onChange={(e) => setFormData({...formData, quantidade_estoque: e.target.value})}
              />
            </div>
          </div>

          <button type="submit" className="w-full bg-blue-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-blue-700 shadow-lg shadow-blue-200 transition flex items-center justify-center gap-2">
            <Save size={20} /> {state?.item ? 'Atualizar Produto' : 'Gravar Produto'}
          </button>
        </form>
      </div>
    </main>
  );
}
